#include <stdio.h>
#include <stdlib.h>

// Function to check if an array is an arithmetic progression
int is_arithmetic_progression(int arr[], int n) {
    if (n < 2) return 0;
    int diff = arr[1] - arr[0];
    for (int i = 2; i < n; i++) {
        if (arr[i] - arr[i-1] != diff) return 0;
    }
    return 1;
}

// Function to check if an array is a geometric progression
int is_geometric_progression(int arr[], int n) {
    if (n < 2) return 0;
    int ratio = arr[1] / arr[0];
    for (int i = 2; i < n; i++) {
        if (arr[i] / arr[i-1] != ratio) return 0;
    }
    return 1;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int arr[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &arr[i]);
        }
        // Generate all possible subsets and check if they form an arithmetic or geometric progression
        for (int mask = 1; mask < (1 << N); mask++) {
            int subset[N], subset_size = 0;
            for (int i = 0; i < N; i++) {
                if ((mask & (1 << i))) {
                    subset[subset_size++] = arr[i];
                }
            }
            if (is_arithmetic_progression(subset, subset_size)) {
                printf("Arithmetic Progression: ");
                for (int i = 0; i < subset_size; i++) {
                    printf("%d ", subset[i]);
                }
                printf("\n");
            }
            if (is_geometric_progression(subset, subset_size)) {
                printf("Geometric Progression: ");
                for (int i = 0; i < subset_size; i++) {
                    printf("%d ", subset[i]);
                }
                printf("\n");
            }
        }
    }
    return 0;
}

